#!/usr/bin/env node
'use strict';

const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');
const { spawnSync } = require('node:child_process');

const ROOT = path.resolve(__dirname, '..');
const SOURCE = path.join(ROOT, 'lib', 'sdk', 'index.types.ts');
const OUTPUT = path.join(ROOT, 'lib', 'sdk', 'index.d.ts');
const HEADER = [
  '// AUTO-GENERATED by scripts/generate-sdk-types.cjs.',
  '// Edit lib/sdk/index.types.ts and run `npm run generate:sdk-types`.',
  '',
].join('\n');

function compileDeclaration(options = {}) {
  const sourcePath = options.sourcePath || SOURCE;
  const typescriptPath = options.typescriptPath
    || path.join(ROOT, 'node_modules', 'typescript', 'bin', 'tsc');
  const temporary = fs.mkdtempSync(path.join(os.tmpdir(), 'oxe-sdk-declarations-'));
  try {
    const compiled = spawnSync(process.execPath, [
      typescriptPath,
      sourcePath,
      '--declaration',
      '--emitDeclarationOnly',
      '--module',
      'commonjs',
      '--moduleResolution',
      'node',
      '--target',
      'ES2020',
      '--strict',
      '--skipLibCheck',
      'false',
      '--outDir',
      temporary,
    ], { cwd: ROOT, encoding: 'utf8', maxBuffer: 8 * 1024 * 1024 });
    if (compiled.error || compiled.status !== 0) {
      throw new Error([
        'TypeScript não conseguiu gerar as declarações do SDK',
        compiled.error && compiled.error.message,
        compiled.stdout,
        compiled.stderr,
      ].filter(Boolean).join('\n'));
    }
    const emittedName = `${path.basename(sourcePath, path.extname(sourcePath))}.d.ts`;
    const pending = [temporary];
    while (pending.length > 0) {
      const directory = pending.pop();
      for (const entry of fs.readdirSync(directory, { withFileTypes: true })) {
        const target = path.join(directory, entry.name);
        if (entry.isDirectory()) pending.push(target);
        else if (entry.name === emittedName) return fs.readFileSync(target, 'utf8');
      }
    }
    throw new Error(`TypeScript não emitiu ${emittedName}`);
  } finally {
    fs.rmSync(temporary, { recursive: true, force: true });
  }
}

function render(options = {}) {
  const declaration = compileDeclaration(options);
  return HEADER + declaration.replace(/\r\n/g, '\n').replace(/\s*$/, '\n');
}

function generate(options = {}) {
  const outputPath = options.outputPath || OUTPUT;
  const expected = render(options);
  const actual = fs.existsSync(outputPath) ? fs.readFileSync(outputPath, 'utf8').replace(/\r\n/g, '\n') : '';
  if (options.check) {
    if (actual !== expected) {
      throw new Error('lib/sdk/index.d.ts divergiu de lib/sdk/index.types.ts; execute npm run generate:sdk-types');
    }
    return false;
  }
  if (actual === expected) return false;
  fs.writeFileSync(outputPath, expected, 'utf8');
  return true;
}

function main(argv = process.argv.slice(2)) {
  const check = argv.includes('--check');
  try {
    const changed = generate({ check });
    console.log(check ? 'sdk-types: OK (sem drift)' : `sdk-types: ${changed ? 'gerado' : 'atualizado'}`);
    return 0;
  } catch (error) {
    console.error(`sdk-types: BLOCKED: ${error.message}`);
    return 1;
  }
}

if (require.main === module) process.exitCode = main();

module.exports = { HEADER, SOURCE, OUTPUT, compileDeclaration, render, generate, main };
